import React, { useEffect, useRef, useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";

// ── Icons ──────────────────────────────────────────────
const HomeIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
    <path d="M3 12L12 3l9 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M5 10v11h14V10" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M9 21V12h6v9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

const RetryIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
    <path d="M3 12a9 9 0 1 0 9-9 9 9 0 0 0-6.36 2.64L3 8" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
    <path d="M3 3v5h5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

const DownloadIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
    <path d="M12 3v12M8 11l4 4 4-4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M3 17v2a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-2" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
  </svg>
);

// ── Particle Banner ────────────────────────────────────
function ParticleBanner({ granted }) {
  const canvasRef = useRef(null);
  const color = granted ? "#06d6a0" : "#f72585";

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    canvas.width  = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;

    const particles = Array.from({ length: 55 }, () => ({
      x:  Math.random() * canvas.width,
      y:  Math.random() * canvas.height,
      r:  Math.random() * 2 + 0.5,
      dx: (Math.random() - 0.5) * 0.4,
      dy: (Math.random() - 0.5) * 0.4,
      o:  Math.random() * 0.5 + 0.1,
    }));

    let raf;
    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach((p) => {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = color + Math.floor(p.o * 255).toString(16).padStart(2, "0");
        ctx.fill();
        p.x += p.dx; p.y += p.dy;
        if (p.x < 0 || p.x > canvas.width)  p.dx *= -1;
        if (p.y < 0 || p.y > canvas.height)  p.dy *= -1;
      });
      raf = requestAnimationFrame(draw);
    };
    draw();
    return () => cancelAnimationFrame(raf);
  }, [color]);

  return <canvas ref={canvasRef} className="particle-canvas" />;
}

// ── Score Ring ─────────────────────────────────────────
function ScoreRing({ score, granted }) {
  const [animated, setAnimated] = useState(0);
  const radius = 54;
  const stroke  = 7;
  const circ    = 2 * Math.PI * radius;
  const color   = granted ? "#06d6a0" : score > 40 ? "#ffd166" : "#f72585";
  const offset  = circ - (animated / 100) * circ;

  useEffect(() => {
    let start = null;
    const duration = 1200;
    const target   = Math.min(100, Math.max(0, score));
    const step = (ts) => {
      if (!start) start = ts;
      const p    = Math.min((ts - start) / duration, 1);
      const ease = 1 - Math.pow(1 - p, 3);
      setAnimated(ease * target);
      if (p < 1) requestAnimationFrame(step);
    };
    const t = setTimeout(() => requestAnimationFrame(step), 300);
    return () => clearTimeout(t);
  }, [score]);

  return (
    <div className="score-ring-wrap">
      <svg width={130} height={130} viewBox="0 0 130 130">
        <circle cx="65" cy="65" r={radius} fill="none"
          stroke="rgba(255,255,255,0.06)" strokeWidth={stroke} />
        <circle cx="65" cy="65" r={radius} fill="none"
          stroke={color} strokeWidth={stroke}
          strokeDasharray={circ} strokeDashoffset={offset}
          strokeLinecap="round"
          transform="rotate(-90 65 65)"
          style={{ filter: `drop-shadow(0 0 6px ${color}66)` }}
        />
        <text x="65" y="60" textAnchor="middle" className="ring-value" style={{ fill: color }}>
          {Math.round(animated)}
        </text>
        <text x="65" y="76" textAnchor="middle" className="ring-label">
          SCORE
        </text>
      </svg>
      <span className="ring-subtitle">Security Score</span>
    </div>
  );
}

// ── Hero Banner ────────────────────────────────────────
function HeroBanner({ granted, isFake, status, reason, score }) {
  const color   = granted ? "#06d6a0" : isFake ? "#f72585" : "#ffd166";
  const label   = granted ? "ACCESS GRANTED" : isFake ? "SPOOFING DETECTED" : "ACCESS DENIED";
  const bannerClass = granted ? "result-banner granted" : isFake ? "result-banner fake" : "result-banner denied";

  return (
    <div className={bannerClass} style={{ borderLeftColor: color }}>
      <ParticleBanner granted={granted} />

      <div className="banner-left">
        <div className="banner-badge" style={{ background: `${color}22`, border: `1px solid ${color}44` }}>
          <span className="banner-dot" style={{ background: color, boxShadow: `0 0 8px ${color}` }} />
          <span className="banner-badge-text" style={{ color }}>{label}</span>
        </div>
        <h2 className="banner-status" style={{ color }}>{status}</h2>
        {reason && <p className="banner-reason">{reason}</p>}
      </div>

      <div className="banner-right">
        <ScoreRing score={score} granted={granted} />
      </div>
    </div>
  );
}

// ── Confidence Meter ───────────────────────────────────
function ConfidenceMeter({ label, value, colorStart, colorEnd, delay = 0 }) {
  const [width, setWidth] = useState(0);

  useEffect(() => {
    const t = setTimeout(() => setWidth(Math.min(100, Math.max(0, value))), 500 + delay);
    return () => clearTimeout(t);
  }, [value, delay]);

  return (
    <div className="confidence-meter">
      <div className="confidence-header">
        <span className="confidence-label">{label}</span>
        <span className="confidence-value">{value?.toFixed(1)}%</span>
      </div>
      <div className="confidence-track">
        <div
          className="confidence-fill"
          style={{
            width: `${width}%`,
            background: `linear-gradient(90deg, ${colorStart}, ${colorEnd})`,
            boxShadow: `0 0 8px ${colorEnd}66`,
          }}
        />
      </div>
    </div>
  );
}

// ── Auth Timeline ──────────────────────────────────────
function AuthTimeline({ granted, isFake }) {
  const steps = [
    { label: "Voice Received",      desc: "Audio captured and preprocessed",    color: "#4361ee", done: true },
    { label: "Speaker Verification",desc: "ECAPA-TDNN embedding comparison",     color: granted || !isFake ? "#4361ee" : "#f72585", done: true },
    { label: "Deepfake Detection",  desc: "AASIST anti-spoofing analysis",       color: isFake ? "#f72585" : "#4361ee", done: true },
    { label: "Decision",            desc: granted ? "Access granted" : "Access denied", color: granted ? "#06d6a0" : "#f72585", done: true },
  ];

  return (
    <div className="timeline">
      {steps.map((step, i) => (
        <div key={i} className="timeline-item">
          <div className="timeline-track">
            <div className="timeline-dot" style={{ background: `${step.color}22`, border: `2px solid ${step.color}` }}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none">
                <path d="M5 12l5 5L19 7" stroke={step.color} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </div>
            {i < steps.length - 1 && (
              <div className="timeline-line" style={{
                background: `linear-gradient(to bottom, ${step.color}44, ${steps[i + 1].color}22)`
              }} />
            )}
          </div>
          <div className="timeline-content" style={{ animationDelay: `${i * 0.12}s` }}>
            <div className="timeline-label">{step.label}</div>
            <div className="timeline-desc">{step.desc}</div>
          </div>
        </div>
      ))}
    </div>
  );
}

// ── Main Result Page ───────────────────────────────────
export default function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const data     = location.state?.data;

  if (!data) {
    return (
      <div className="auth-page">
        <div className="auth-container result-empty">
          <p>No authentication result found.</p>
          <button className="btn btn-primary" onClick={() => navigate("/login")}>
            Go to Login
          </button>
        </div>
      </div>
    );
  }

  const isGranted     = data.access === "Granted";
  const isFake        = data.status?.toLowerCase().includes("fake");
  const isMismatch    = data.status?.toLowerCase().includes("mismatch");
  const securityScore = isGranted
    ? Math.round((data.similarity + data.real_prob) / 2)
    : isMismatch
    ? Math.round(data.similarity)
    : Math.round((data.fake_prob + (100 - data.similarity)) / 2);

  return (
    <div className="result-page">
      <div className="orb orb-blue" />
      <div className="orb orb-purple" />

      <div className="result-container">

        {/* Navigation */}
        <div className="result-actions-top">
          <button className="btn btn-ghost" onClick={() => navigate("/")}>
            <HomeIcon /> Home
          </button>
          <button className="btn btn-ghost" onClick={() => navigate("/login")}>
            <RetryIcon /> Try Again
          </button>
        </div>

        <div className="result-card-wrap">

          {/* 1 — Hero Banner */}
          <HeroBanner
            granted={isGranted}
            isFake={isFake}
            status={data.status}
            reason={data.reason}
            score={securityScore}
          />

          {/* 2 — Stats */}
          <div className="stats-row">
            {[
              { label: "Similarity", value: data.similarity, color: "var(--cyan)" },
              { label: "Real Prob.", value: data.real_prob,  color: "var(--green)" },
              { label: "Fake Prob.", value: data.fake_prob,  color: "var(--pink)" },
              ...(data.distance != null
                ? [{ label: "Distance", value: data.distance, color: "var(--yellow)", raw: true }]
                : []),
            ].map((s) => (
              <div className="stat-card" key={s.label}>
                <div className="stat-value" style={{ color: s.color }}>
                  {s.raw ? s.value : `${s.value?.toFixed(1)}%`}
                </div>
                <div className="stat-label">{s.label}</div>
              </div>
            ))}
          </div>

          {/* 3 — Confidence + Timeline */}
          <div className="result-two-col">
            <div className="result-section">
              <h3 className="section-title">Confidence Meters</h3>
              <ConfidenceMeter label="Speaker Similarity" value={data.similarity} colorStart="#4361ee" colorEnd="#7b2ff7" delay={0} />
              {data.real_prob > 0 && <ConfidenceMeter label="Real Voice"       value={data.real_prob}  colorStart="#06d6a0" colorEnd="#059669" delay={120} />}
              {data.fake_prob > 0 && <ConfidenceMeter label="Deepfake Risk"    value={data.fake_prob}  colorStart="#f72585" colorEnd="#7b2ff7" delay={240} />}
              {isMismatch && data.real_prob === 0 && data.fake_prob === 0 && (
                <p className="meter-skip-note">Deepfake analysis skipped — speaker mismatch detected.</p>
              )}
            </div>

            <div className="result-section">
              <h3 className="section-title">Authentication Steps</h3>
              <AuthTimeline granted={isGranted} isFake={isFake} />
            </div>
          </div>

          {/* 4 — Spectrograms */}
          {(data.reg_spec || data.login_spec) && (
            <div className="result-section">
              <h3 className="section-title">Voice Spectrograms</h3>
              <div className="spec-grid">
                {data.reg_spec   && <div className="spec-item"><p className="spec-label">Registered Voice</p><img src={data.reg_spec}   alt="Registered spectrogram" className="spec-img" /></div>}
                {data.login_spec && <div className="spec-item"><p className="spec-label">Login Voice</p>     <img src={data.login_spec} alt="Login spectrogram"      className="spec-img" /></div>}
              </div>
            </div>
          )}

          {/* 5 — GradCAM */}
          {data.grad_img && (
            <div className="result-section result-section--cyan">
              <h3 className="section-title section-title--cyan">Deepfake Explanation (GradCAM)</h3>
              <p className="section-desc">Highlights which audio regions triggered the deepfake detection model.</p>
              <img src={data.grad_img} alt="GradCAM explanation" className="spec-img" />
            </div>
          )}

          {/* 6 — LIME */}
          {data.lime_img && (
            <div className="result-section result-section--purple">
              <h3 className="section-title section-title--purple">Deepfake Explanation (LIME)</h3>
              <p className="section-desc">LIME highlights the most influential audio segments that affected the model's prediction.</p>
              <img src={data.lime_img} alt="LIME explanation" className="spec-img" />
            </div>
          )}

          {/* 7 — Download */}
          {data.report && (
            <div className="result-actions">
              <a href={data.report} target="_blank" rel="noreferrer" className="btn btn-primary">
                <DownloadIcon /> Download Report
              </a>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}
